### 2.3 Créer `engine/src/learner_profile.rs`

```rust
use panini_core::aggregable::digest::{AggregationResult, BasicAggregator};
use lc_core::aggregable::Aggregator;
use lc_core::domain::ExtractedFeature;
use lc_core::traits::LinguisticDefinition;

/// Agrégateur spécifique au profil apprenant Panglot
pub struct LearnerProfileAggregator<M, F> {
    morph_agg: BasicAggregator<ExtractedFeature<M>>,
    seg_agg: Option<BasicAggregator<WordSegmentation<F>>>,
}

impl<M, F> LearnerProfileAggregator<M, F>
where
    M: Aggregable + Clone,
    F: AggregableFields + Clone,
{
    pub fn new() -> Self;

    pub fn record_feature(&mut self, feature: &ExtractedFeature<M>);

    pub fn record_segmentation(&mut self, seg: &WordSegmentation<F>);

    /// Format YAML compact pour prompt LLM
    pub fn to_llm_summary(&self, max_lemmas: usize) -> String;

    /// Features jamais/peu vues (pour éviter répétitions)
    pub fn unseen_features(&self, threshold: usize) -> Vec<FeatureKey>;

    /// Stats par skill node (si tracking activé)
    pub fn stats_by_skill(&self) -> HashMap<String, SkillStats>;

    pub fn finish(self) -> AggregationResult;
}
```

#### **`to_llm_summary()` — Format YAML**

```yaml
Noun:
  total: 142
  case:
    coverage: "5/7"
    distribution:
      Nominative: 45
      Accusative: 38
      Dative: 22
      # ... (omit unseen)
  lemma:
    unique: 87
    top: [pies(12), kot(8), dom(7), ...]

Verb:
  total: 98
  tense:
    coverage: "2/4"
    distribution:
      Present: 52
      Past: 34
```

